#define SPHERE_RADIUS 0.1
#define SPHERE_DENSITY 1000.0 // kg/m^3 for water, let's say
#define AIR_DENSITY 1.225 // kg/m^3
#define AIR_VISCOSITY 1.81e-5 // Pa*s
#define GRAVITY 9.81 // m/s^2

// Define our parameterized airspeed (let's say it's a variable 'airspeed')
#define AIRSPEED 10.0 // m/s

// Function to calculate Reynolds number
inline scalar ReynoldsNumber(scalar diameter, scalar velocity, scalar viscosity) {
    return diameter * velocity / viscosity;
}

// Function to calculate drag force on a sphere
inline scalar DragForce(scalar diameter, scalar velocity, scalar rho) {
    return 0.5 * 0.47 * PI * pow(diameter, 2) * rho * velocity * velocity;
}

int main(int argc, char *argv[]) {
    Info << "Starting analysis of a sphere with airspeed parameterization." << endl;

    // Sphere properties
    scalar diameter = 2 * SPHERE_RADIUS;
    scalar reynoldsNumber = ReynoldsNumber(diameter, AIRSPEED, AIR_VISCOSITY);
    scalar dragForce = DragForce(diameter, AIRSPEED, AIR_DENSITY);

    Info << "Sphere diameter: " << diameter << " m" << endl;
    Info << "Reynolds Number: " << reynoldsNumber << endl;
    Info << "Drag Force: " << dragForce << " N" << endl;

    Info << "Analysis complete." << endl;

    return 0;
}
